#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-27

# cc-stale-belowfloor.sh — label open cc-adoption FEATURE issues whose CC
# version is below the supported floor as `cc-stale`.
#
# Bounds the rolling "CC adoption" umbrella by making moot issues queryable and
# visually separable WITHOUT closing them — per project policy, issues close
# only when a PR merges (`Closes #N`), never via a script. A below-floor
# adoption item is de-facto deprioritized: the floor moved past it, so it's a
# candidate for the human to close (or to keep, by removing the label).
#
# CATEGORY GUARD: `breaking` and `new_perm` items are NEVER auto-staled. Their
# behavior persists at the current floor (below-floor only means the feature is
# now universally available), so they are live adoption work — not moot. Keying
# staleness on version alone wrongly buried these (security/permission behaviors);
# the category is read from the issue body's `**Category:** \`...\`` line. Only
# non-breaking, non-perm features below the floor are auto-staled.
#
# Idempotent self-heal: already-labeled issues are skipped, and non-version
# issues (manual-triage / token-rotation) are ignored. Safe on every cron tick.
#
# Inputs (env):
#   GH_REPO        "owner/repo" — required (workflow injects ${{ github.repository }})
#   SUPPORT_FILE   path to cc-support.json (default shared/cc-support.json)
#   STALE_LABEL    label name (default cc-stale)
#   DRY_RUN        "1" → print actions, mutate nothing (default "0")
#   SLEEP_BETWEEN  seconds between write calls (default 1; dodges gh secondary limit)
#
# Exit 0 on success (including no-op). Hard-fails on missing GH_REPO or gh errors.

set -euo pipefail

GH_REPO="${GH_REPO:?GH_REPO is required (owner/repo)}"
SUPPORT_FILE="${SUPPORT_FILE:-shared/cc-support.json}"
STALE_LABEL="${STALE_LABEL:-cc-stale}"
DRY_RUN="${DRY_RUN:-0}"
SLEEP_BETWEEN="${SLEEP_BETWEEN:-1}"

note() { echo "[cc-stale] $*"; }
maybe_sleep() { [ "$DRY_RUN" = "1" ] || sleep "$SLEEP_BETWEEN"; }

# semver strict-less-than: 0 (true) when $1 < $2, else 1.
ver_lt() {
  [ "$1" != "$2" ] && [ "$(printf '%s\n%s\n' "$1" "$2" | sort -V | head -1)" = "$1" ]
}

if [ ! -s "$SUPPORT_FILE" ]; then
  note "no $SUPPORT_FILE — nothing to do."
  exit 0
fi
FLOOR=$(jq -r '.supported_floor // empty' "$SUPPORT_FILE")
if [ -z "$FLOOR" ]; then
  note "no supported_floor in $SUPPORT_FILE — nothing to do."
  exit 0
fi
note "supported_floor = ${FLOOR}"

# Ensure the label exists, resiliently. The old `gh label list | grep -qx … && create`
# pipeline died under `set -e` when `gh label list` hit a transient 403 (the LIST
# stage failed → the script aborted before reaching create — issue #2036 sibling).
# Here we (1) propagate a genuine list failure LOUDLY so the run can retry, (2) skip
# when present, (3) tolerate the create-race where another run made the label first
# (gh exits non-zero with "already exists" on stderr — NOT a magic exit code).
ensure_label() {
  local existing
  if ! existing=$(gh label list -R "$GH_REPO" --json name --jq '.[].name'); then
    echo "[cc-stale] ERROR: 'gh label list' failed (transient gh/network/403?) — aborting so the run retries." >&2
    return 1
  fi
  if printf '%s\n' "$existing" | grep -qx "$STALE_LABEL"; then
    return 0
  fi
  local out
  if out=$(gh label create "$STALE_LABEL" -R "$GH_REPO" --color BFBFBF \
        --description "CC-adoption item below the support floor — moot, candidate for close" 2>&1); then
    note "created label ${STALE_LABEL}"
    return 0
  fi
  # gh's duplicate-label error is GraphQL "Name has already been taken"; REST/other
  # paths say "already exists". Match both so the race is tolerated either way.
  if printf '%s' "$out" | grep -qiE 'already (exists|been taken)'; then
    note "label ${STALE_LABEL} already exists (race) — continuing"
    return 0
  fi
  echo "[cc-stale] ERROR: 'gh label create' failed: ${out}" >&2
  return 1
}

if [ "$DRY_RUN" != "1" ]; then
  ensure_label || exit 1
fi

labeled=0
skipped=0
while IFS=$'\t' read -r NUM TITLE LABELS CAT; do
  [ -z "${NUM:-}" ] && continue
  # Only per-version feature issues carry a version in the title
  # ("adopt CC X.Y.Z feature: ..."). manual-triage / token-rotation issues
  # name no single version → leave them alone. Use a bash regex (a conditional,
  # so a no-match does NOT trip `set -e` the way a failing grep pipeline would).
  VER=""
  if [[ "$TITLE" =~ CC[[:space:]]([0-9]+\.[0-9]+\.[0-9]+) ]]; then
    VER="${BASH_REMATCH[1]}"
  fi
  if [ -z "$VER" ]; then
    continue
  fi
  case ",${LABELS}," in
    *",${STALE_LABEL},"*)
      skipped=$((skipped + 1))
      continue
      ;;
  esac
  # Category guard: NEVER auto-stale `breaking` changes or `new_perm` capabilities.
  # Their behavior persists at the current floor (below-floor just means the
  # feature is now universally available), so they are live adoption work, not
  # moot. Keying staleness on version alone mislabeled these as moot — verified
  # 6/12 (security/permission behaviors). Only non-breaking, non-perm features
  # below the floor are auto-staled.
  case "$CAT" in
    breaking|new_perm)
      note "skip #${NUM}: category=${CAT} persists at floor — not auto-staled (CC ${VER})"
      skipped=$((skipped + 1))
      continue
      ;;
  esac
  if ver_lt "$VER" "$FLOOR"; then
    if [ "$DRY_RUN" = "1" ]; then
      note "DRY_RUN: would label #${NUM} \"${STALE_LABEL}\" (CC ${VER} < floor ${FLOOR})"
    else
      gh issue edit "$NUM" -R "$GH_REPO" --add-label "$STALE_LABEL" >/dev/null
      gh issue comment "$NUM" -R "$GH_REPO" --body "Auto-flagged \`${STALE_LABEL}\`: CC ${VER} is below the current support floor (${FLOOR}), so this adoption item is likely moot. Close it if no longer relevant, or remove the label to keep it active." >/dev/null
      note "labeled #${NUM} (CC ${VER} < floor ${FLOOR})"
      maybe_sleep
    fi
    labeled=$((labeled + 1))
  fi
done < <(gh issue list -R "$GH_REPO" --label cc-adoption --state open --limit 300 \
  --json number,title,labels,body \
  --jq '.[] | [
      .number,
      .title,
      ([.labels[].name] | join(",")),
      (((.body // "") | (capture("Category[^`]*`(?<c>[a-z_]+)`")?.c)) // "unknown")
    ] | @tsv')

note "done: labeled=${labeled}, already-stale skipped=${skipped}."
